import{_ as t,o as a,c as l,ag as n}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Tmux Aliase | Dotfiles (DE)","titleTemplate":":title","description":"Shell-Aliase fuer tmux Terminal-Multiplexer. Sessions, Fenster und Panes effizient verwalten. Kompatibel mit macOS, Linux und WSL via Dotfiles.","frontmatter":{"title":"Tmux Aliase | Dotfiles","description":"Shell-Aliase fuer tmux Terminal-Multiplexer. Sessions, Fenster und Panes effizient verwalten. Kompatibel mit macOS, Linux und WSL via Dotfiles.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Tmux Aliase preview","canonical":"/de/aliases/tmux/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Tmux Aliase","pageType":"docs","schemaType":"WebPage","metaTitle":"Tmux Aliase - Dotfiles (DE)","permalink":"/de/aliases/tmux/","sidebar":true,"meta":[{"name":"keywords","content":"tmux aliase, terminal multiplexer, tmux session, tmux verknuepfungen, dotfiles, shell"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Tmux Aliase - Dotfiles"},{"name":"twitter:description","content":"Shell-Aliase fuer tmux Terminal-Multiplexer. Sessions, Fenster und Panes verwalten."},{"name":"og:title","content":"Tmux Aliase - Dotfiles"},{"name":"og:description","content":"Shell-Aliase fuer tmux Terminal-Multiplexer. Sessions, Fenster und Panes verwalten."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/aliases/tmux/index.md","filePath":"de/aliases/tmux/index.md","lastUpdated":1773010926000}'),i={name:"de/aliases/tmux/index.md"};function s(r,e,d,o,u,m){return a(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="tmux-aliase" tabindex="-1">Tmux Aliase <a class="header-anchor" href="#tmux-aliase" aria-label="Permalink to &quot;Tmux Aliase&quot;">​</a></h1><p>Leistungsstarke Terminal-Multiplexing mit intuitiven Verknuepfungen.</p><h2 id="uebersicht" tabindex="-1">Uebersicht <a class="header-anchor" href="#uebersicht" aria-label="Permalink to &quot;Uebersicht&quot;">​</a></h2><p>Diese Aliase sind in <code>tmux.aliases.sh</code> definiert und werden automatisch von Chezmoi geladen. Sie bieten schnellen Zugriff auf tmux Session-Verwaltung und Navigation.</p><h2 id="referenz" tabindex="-1">Referenz <a class="header-anchor" href="#referenz" aria-label="Permalink to &quot;Referenz&quot;">​</a></h2><h3 id="session-verwaltung" tabindex="-1">Session-Verwaltung <a class="header-anchor" href="#session-verwaltung" aria-label="Permalink to &quot;Session-Verwaltung&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>tm</code></td><td style="text-align:left;">tmux starten</td></tr><tr><td style="text-align:left;"><code>tma</code></td><td style="text-align:left;">Letzte Session anhaengen</td></tr><tr><td style="text-align:left;"><code>tmat</code></td><td style="text-align:left;">Bestimmte Session anhaengen</td></tr><tr><td style="text-align:left;"><code>tmn</code></td><td style="text-align:left;">Neue unbenannte Session</td></tr><tr><td style="text-align:left;"><code>tms</code></td><td style="text-align:left;">Neue benannte Session</td></tr><tr><td style="text-align:left;"><code>tml</code></td><td style="text-align:left;">Alle Sessions auflisten</td></tr><tr><td style="text-align:left;"><code>tmks</code></td><td style="text-align:left;">Alle Sessions ausser der aktuellen beenden</td></tr><tr><td style="text-align:left;"><code>tmka</code></td><td style="text-align:left;">Alle Sessions beenden (Server)</td></tr></tbody></table><h3 id="fenster-und-panes" tabindex="-1">Fenster und Panes <a class="header-anchor" href="#fenster-und-panes" aria-label="Permalink to &quot;Fenster und Panes&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>tmls</code></td><td style="text-align:left;">Fenster auflisten</td></tr><tr><td style="text-align:left;"><code>tmlp</code></td><td style="text-align:left;">Panes auflisten</td></tr></tbody></table><h3 id="konfiguration" tabindex="-1">Konfiguration <a class="header-anchor" href="#konfiguration" aria-label="Permalink to &quot;Konfiguration&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>tmr</code></td><td style="text-align:left;">tmux-Konfiguration neu laden</td></tr><tr><td style="text-align:left;"><code>tmi</code></td><td style="text-align:left;">tmux-Info anzeigen</td></tr></tbody></table><h2 id="schluesselmerkmale" tabindex="-1">Schluesselmerkmale <a class="header-anchor" href="#schluesselmerkmale" aria-label="Permalink to &quot;Schluesselmerkmale&quot;">​</a></h2><ul><li>Modernes Farbschema mit OS-spezifischer Statusleiste</li><li>Intuitive Keybindings mit <code>Ctrl+a</code> als Prefix-Taste</li><li>Umfassende Fenster- und Pane-Verwaltung</li><li>Session-Persistenz mit tmux-resurrect und tmux-continuum</li><li>Scrollbares Hilfe-Menue (<code>Ctrl+a ?</code>)</li><li>Mausunterstuetzung fuer einfache Navigation</li></ul><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><p>Druecken Sie <code>Ctrl+a ?</code>, um alle Keybindings zu sehen. Wichtige Funktionen:</p><ul><li><strong>Fensterverwaltung</strong> - Splitten, erstellen, navigieren und umbenennen</li><li><strong>Pane-Navigation</strong> - Zwischen Panes mit Vim-Keys h/j/k/l wechseln</li><li><strong>Session-Verwaltung</strong> - Sessions erstellen, umbenennen und wechseln</li><li><strong>Copy-Mode</strong> - Vim-aehnliche Auswahl, Suche und Clipboard-Integration</li></ul>',16)])])}const f=t(i,[["render",s]]);export{h as __pageData,f as default};
